import { action, observable } from 'mobx';
import Routes from '@/../config/routes.config';

export class UIStore {
    @observable
    navTitle: string = Routes[0].routes[0].title; // 导航标题

    @observable
    ifLoading = false; // 是否展示loading

    @observable
    activeMenuKey: string = Routes[0].routes[0].key; // 当前展示页面的菜单索引

    @observable
    ifResize = false; // 在窗口变化时取反，作为图表的一个属性，从而控制其跟随窗口尺寸变化重新渲染

    // 有时候loading的引用状态可能不是最新的，toggle方法可能会出现隐藏不掉的情况 所以拆分成open 和 close
    @action
    openLoading = () => {
        this.ifLoading = true;
    };
    @action
    closeLoading = () => {
        this.ifLoading = false;
    };

    @action
    setTitle = (title: string) => {
        this.navTitle = title;
    };

    @action
    setMenu = (key: string) => {
        this.activeMenuKey = key;
    };

    @action
    changeResize = () => (this.ifResize = !this.ifResize);
}

const uiStore = new UIStore();
export default uiStore;
