import { action, observable, runInAction } from 'mobx';
import { IResponse, get } from '@/utils/request';
import { IStationData, IDefendData, IPriceItem, initStationData, initDefendData } from './typings';

const { APP_SERVICE, WEBSOCKET_SERVER, ANALYSIS_SERVER } = APP_CONFIG;

export class StatisticsStore {
    @observable
    stationStatistics: IStationData = initStationData;

    @observable
    defendStatistics: IDefendData = initDefendData;

    @observable
    priceList: IPriceItem[] = []; // 营收列表

    /**
     * 获取站点各项数据统计情况
     */
    @action
    getStationStatistics = async (): Promise<IResponse> => {
        try {
            const result = await get(`${APP_SERVICE}front/mapic/getFactoryCountForMy`);
            result &&
                result.data &&
                runInAction(() => {
                    this.stationStatistics = result.data;
                });
            return result;
        } catch (e) {
            return e;
        }
    };

    /**
     * 获取维护站点各项数据统计情况
     */
    @action
    getDefendStatistics = async (): Promise<IResponse> => {
        try {
            const result = await get(`${APP_SERVICE}front/mapic/countFactoryMaintenanceInfoForMy`);
            result &&
                result.data &&
                runInAction(() => {
                    this.defendStatistics = result.data;
                });
            return result;
        } catch (e) {
            return e;
        }
    };

    /**
     * 获取运营数据统计情况
     * @param {string} startTime 开始时间
     * @param {string} endTime 结束时间
     */
    @action
    getBusinessStatistics = async (startTime: string, endTime: string): Promise<IResponse> => {
        try {
            const SERVER_ID = 2002;
            const result = await get(`${WEBSOCKET_SERVER}washData/countWashMachinelogToday`, {
                serviceId: SERVER_ID,
                startTime,
                endTime
            });
            return result;
        } catch (e) {
            return e;
        }
    };
}

const statisticsStore = new StatisticsStore();
export default statisticsStore;
